#!/usr/bin/env node
"use strict";

/**
 * Regenerates the icon-wobble filter registry (issue #271).
 *
 * The wobble effect applies an SVG `feTurbulence` → `feDisplacementMap` filter
 * to every lucide icon via CSS `filter: url(#wob-<name>)`. This script discovers
 * which lucide icons the app actually uses, bakes a deterministic seed for each,
 * and emits two committed artifacts (CI diff-checks them, like every other
 * generated file):
 *
 *   - lib/wobble/wobble-registry.generated.ts  → the { name, seed } list the
 *     `WobbleFilters` component renders one <filter> from, per distinct name.
 *   - app/wobble.generated.css                 → the per-name `.lucide-<name>
 *     { filter: url(#wob-<name>) }` rules (+ overflow + `.no-wobble` opt-out).
 *
 * Icon names are read authoritatively by rendering each imported lucide export
 * and extracting its runtime `lucide-<kebab>` class — never re-derived from the
 * identifier, because aliases lie (e.g. `Loader2Icon` renders `lucide-loader-
 * circle`, and `CheckIcon`/`Check` both render `lucide-check`).
 *
 * Run via `npm run generate`.
 */

const fs = require("fs");
const path = require("path");
const React = require("react");
const { renderToStaticMarkup } = require("react-dom/server");
const lucide = require("lucide-react");
const { seedFor } = require("./lib/wobble-hash");

const ROOT = path.resolve(__dirname, "..", "..");
const SCAN_DIRS = ["app", "components", "lib"].map((d) => path.join(ROOT, d));
const SCAN_EXTENSIONS = new Set([".ts", ".tsx"]);
const REGISTRY_OUT = path.join(ROOT, "lib", "wobble", "wobble-registry.generated.ts");
const CSS_OUT = path.join(ROOT, "app", "wobble.generated.css");

/** All `import … from "lucide-react"` specifiers, capturing the `{ … }` block. */
const IMPORT_RE = /import\s+(type\s+)?(?:[\w$]+\s*,\s*)?\{([^}]*)\}\s*from\s*["']lucide-react["']/g;

function walk(dir, out) {
  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      if (entry.name === "node_modules" || entry.name.startsWith(".")) continue;
      walk(full, out);
    } else if (SCAN_EXTENSIONS.has(path.extname(entry.name))) {
      out.push(full);
    }
  }
  return out;
}

/** Collect the original lucide export names imported across the source tree. */
function collectImportedIdentifiers(files) {
  const identifiers = new Set();
  for (const file of files) {
    const source = fs.readFileSync(file, "utf8");
    let match;
    IMPORT_RE.lastIndex = 0;
    while ((match = IMPORT_RE.exec(source)) !== null) {
      const isTypeOnlyImport = Boolean(match[1]);
      if (isTypeOnlyImport) continue; // `import type { LucideIcon } …`
      for (const raw of match[2].split(",")) {
        let spec = raw.trim();
        if (!spec) continue;
        if (spec.startsWith("type ")) continue; // inline `type X` specifier
        // `Original as Local` → the lucide export is `Original`.
        spec = spec.split(/\s+as\s+/)[0].trim();
        if (/^[A-Za-z_$][\w$]*$/.test(spec)) identifiers.add(spec);
      }
    }
  }
  return identifiers;
}

/** Render an export and read its authoritative `lucide-<name>` class, or null. */
function iconClassName(identifier) {
  const Component = lucide[identifier];
  if (!Component) return null; // types (LucideIcon) resolve to undefined at runtime
  try {
    const html = renderToStaticMarkup(React.createElement(Component));
    const match = /lucide\s+lucide-([a-z0-9-]+)/.exec(html);
    return match ? match[1] : null;
  } catch {
    return null; // e.g. the generic `Icon` builder needs an iconNode prop
  }
}

function main() {
  const files = [];
  for (const dir of SCAN_DIRS) {
    if (fs.existsSync(dir)) walk(dir, files);
  }

  const identifiers = [...collectImportedIdentifiers(files)].sort();
  const names = new Set();
  const skipped = [];
  for (const identifier of identifiers) {
    const name = iconClassName(identifier);
    if (name) names.add(name);
    else skipped.push(identifier);
  }

  const registry = [...names]
    .sort()
    .map((name) => ({ name, seed: seedFor(name) }));

  if (registry.length === 0) {
    throw new Error("generate-icon-wobble: no lucide icons discovered — aborting.");
  }

  writeRegistry(registry);
  writeCss(registry);

  console.log(
    `generate-icon-wobble: ${registry.length} icons from ${identifiers.length} imports` +
      (skipped.length ? ` (skipped non-icons: ${skipped.join(", ")})` : ""),
  );
}

function writeRegistry(registry) {
  const lines = registry
    .map(({ name, seed }) => `  { name: ${JSON.stringify(name)}, seed: ${seed} },`)
    .join("\n");
  const contents =
    `// GENERATED by scripts/generate/generate-icon-wobble.js — do not edit.\n` +
    `// Run \`npm run generate\` to refresh. Source of truth for the wobble filter\n` +
    `// registry (issue #271): one entry per distinct lucide icon name in use.\n\n` +
    `export interface WobbleIcon {\n` +
    `  /** The icon's runtime \`lucide-<name>\` class suffix. */\n` +
    `  name: string;\n` +
    `  /** Deterministic base seed for this icon's turbulence noise. */\n` +
    `  seed: number;\n` +
    `}\n\n` +
    `export const WOBBLE_ICONS: WobbleIcon[] = [\n${lines}\n];\n`;
  fs.writeFileSync(REGISTRY_OUT, contents);
}

function writeCss(registry) {
  const rules = registry
    .map(({ name }) => `.lucide-${name} { filter: url(#wob-${name}); }`)
    .join("\n");
  const contents =
    `/* GENERATED by scripts/generate/generate-icon-wobble.js — do not edit. */\n` +
    `/* Run \`npm run generate\` to refresh (issue #271). */\n\n` +
    `/* Room for displaced strokes to bleed past the icon box. */\n` +
    `svg.lucide { overflow: visible; }\n\n` +
    `/* Escape hatch: opt an icon out of the wobble entirely. */\n` +
    `svg.lucide.no-wobble { filter: none; }\n\n` +
    `${rules}\n`;
  fs.writeFileSync(CSS_OUT, contents);
}

main();
